@Override
public void serialize(DateTime value, JsonGenerator gen, SerializerProvider provider)
    throws IOException {
  if (value == null) {
    gen.writeNull();
  } else {
    gen.writeString(ISODateTimeFormat.dateTime().withZoneUTC().print(value));
  }
}

